public class StackHeap {
    // 'value' lives on the heap as part of the object
    private int value;

    public static void main(String[] args) {
        // 'x' is a local primitive — lives on the stack
        int x = 10;

        // 'obj' reference lives on the stack;
        // the StackHeap object itself lives on the heap
        StackHeap obj = new StackHeap();
        obj.value = 42;

        System.out.println("x = " + x);
        System.out.println("obj.value = " + obj.value);
    }
}

