public class Main {
    static int factorial(int n) {
        // Practice: understand stack frames via recursion
        if (n <= 1) return 1;
        return n * factorial(n - 1);
    }

    public static void main(String[] args) {
        // Each call to factorial() pushes a new frame onto the stack
        System.out.println(factorial(5));
        // Try a very large number to trigger StackOverflowError
    }
}

