public class ClassLoaderDemo {
    public static void main(String[] args) {
        // Application class loader
        ClassLoader appCL = ClassLoaderDemo.class.getClassLoader();
        System.out.println("App CL: " + appCL);

        // Platform class loader
        System.out.println("Platform CL: " + appCL.getParent());

        // Bootstrap CL (returns null in Java)
        System.out.println("Bootstrap CL: " + appCL.getParent().getParent());

        // Core class — loaded by Bootstrap CL
        System.out.println("String CL: " + String.class.getClassLoader());
    }
}

