public class Main {
    public static void main(String[] args) {
        // Print the class loader hierarchy for the Main class
        ClassLoader cl = Main.class.getClassLoader();
        while (cl != null) {
            System.out.println(cl);
            cl = cl.getParent();
        }
        System.out.println("Bootstrap (null): " + cl);
    }
}
